/* =========================================
       2. 电脑端样式：当屏幕宽度 >= 768px 时触发
       ========================================= */
    @media screen and (min-width: 768px) {
        .poster-container {
            /* 取消滑动，改为网格平铺 */
            display: grid;
            grid-template-columns: repeat(3, 1fr); /* 一行显示 3 张 */
            gap: 20px; /* 图片之间的间距 */
            overflow-x: visible;
        }
        .poster-item {
            flex: unset; /* 取消手机端的强制全宽 */
            width: 100%; /* 适应网格宽度 */
            scroll-snap-align: none;
        }
        .carousel-hint {
            display: none; /* 电脑端已经是平铺了，隐藏“左右滑动”的提示文本 */
        }
    }
</style>

